// EDIT THESE after import:
return [{ json: {
  owner: 'YOUR_GITHUB_USERNAME',   // e.g. 'arthur-skoobie'
  repo:  'bournemouth-guide',      // the GitHub repo name
  branch: 'main'                   // branch Vercel builds from
} }];

var files = [];
var first = ($input.first() && $input.first().json) || null;
if (Array.isArray(first)) { files = first; } else { files = $input.all().map(function (i) { return i.json; }); }
var existing = {};
files.forEach(function (f) {
  var name = (f && (f.name || f.path)) ? String(f.name || f.path).split('/').pop() : '';
  if (name) existing[name.replace(/\.md$/, '')] = true;
});

// --- CONTENT PLAN: add rows freely. Order = publish priority. ---
var TOPICS = [
  { slug: 'best-time-to-visit-bournemouth', title: 'The Best Time to Visit Bournemouth', keyword: 'best time to visit Bournemouth', category: 'seasonal' },
  { slug: 'bournemouth-on-a-budget', title: 'Bournemouth on a Budget: Free and Cheap Things to Do', keyword: 'cheap things to do in Bournemouth', category: 'things-to-do' },
  { slug: 'dog-friendly-bournemouth', title: 'Dog-Friendly Bournemouth: Beaches, Walks and Places to Stay', keyword: 'dog friendly Bournemouth', category: 'guides' },
  { slug: 'things-to-do-in-bournemouth-when-it-rains', title: 'What to Do in Bournemouth When It Rains', keyword: 'things to do in Bournemouth when it rains', category: 'things-to-do' },
  { slug: 'how-to-get-to-bournemouth', title: 'How to Get to Bournemouth: Train, Car and Airport Guide', keyword: 'how to get to Bournemouth', category: 'guides' },
  { slug: 'bournemouth-nightlife', title: 'Bournemouth Nightlife: Bars, Live Music and Late-Night Eats', keyword: 'Bournemouth nightlife', category: 'food-and-drink' },
  { slug: 'best-fish-and-chips-in-bournemouth', title: 'Where to Find the Best Fish and Chips in Bournemouth', keyword: 'best fish and chips Bournemouth', category: 'food-and-drink' },
  { slug: 'coastal-walks-near-bournemouth', title: 'The Best Coastal Walks Near Bournemouth', keyword: 'coastal walks near Bournemouth', category: 'walking' },
  { slug: 'romantic-things-to-do-in-bournemouth', title: 'A Romantic Weekend in Bournemouth: The Couples Guide', keyword: 'romantic things to do in Bournemouth', category: 'guides' },
  { slug: 'family-days-out-in-bournemouth', title: 'The Best Family Days Out in Bournemouth', keyword: 'family days out Bournemouth', category: 'family' }
];

var next = null;
for (var i = 0; i < TOPICS.length; i++) { if (!existing[TOPICS[i].slug]) { next = TOPICS[i]; break; } }
if (!next) { return []; }  // nothing new to publish today

var SYSTEM = "You are the senior local-SEO editor for The Bournemouth Guide, an independent visitor guide to Bournemouth, Dorset (UK).\nYou write original, genuinely useful, E-E-A-T-strong articles that rank on Google and get cited by AI answer engines (ChatGPT, Perplexity, Google AI Overviews).\n\nHARD RULES:\n- British English. Warm, knowledgeable, first-hand local tone. Never generic AI filler, never 'In conclusion'.\n- 100% ORIGINAL. Never copy any other website. Use only well-known, stable, evergreen facts about Bournemouth.\n- Target the given keyword naturally: in the title, the first sentence, and 2-3 subheadings. Never keyword-stuff.\n- Open with a direct, self-contained answer to the query (2-4 sentences) so it can win featured snippets and AI answers.\n- Then 4-7 sections, each a descriptive '## ' subheading. NO H1 ('# ') anywhere — the title is stored separately.\n- NEVER invent specific prices, phone numbers, opening hours, addresses, or businesses that may not exist. Stay general and evergreen.\n\nINTERNAL LINKS (Markdown): use 3-6 links, only to these existing pages, with natural anchor text:\n  /things-to-do, /things-to-do/beaches, /things-to-do/attractions, /food-and-drink, /food-and-drink/restaurants,\n  /accommodation, /whats-on, /explore, /visitor-information, /ideas-and-inspiration\n\nACCOMMODATION FUNNEL (required, but natural):\n- Include ONE 'where to stay' moment that links to /accommodation.\n- Include EXACTLY ONE contextual mention of Flexiestays linking to https://flexiestays.com — vary the anchor text every article\n  (e.g. 'serviced apartments near the beach', 'Flexiestays aparthotels', 'a flexible short- or long-stay base'), and only where it\n  genuinely helps the reader (serviced apartments / aparthotels close to Bournemouth beach). Never link Flexiestays more than once.\n\nFAQs: 3-4 real-search-intent Q&As, each answer 1-3 sentences.\n\nReturn ONLY the requested structured JSON object. body_markdown is the article body in Markdown (no frontmatter, no H1).";
var SCHEMA = {"type":"object","additionalProperties":false,"properties":{"title":{"type":"string"},"description":{"type":"string"},"tags":{"type":"array","items":{"type":"string"}},"faqs":{"type":"array","items":{"type":"object","additionalProperties":false,"properties":{"question":{"type":"string"},"answer":{"type":"string"}},"required":["question","answer"]}},"body_markdown":{"type":"string"}},"required":["title","description","tags","faqs","body_markdown"]};

var user = 'Write the article now.\n'
  + 'Target keyword: "' + next.keyword + '".\n'
  + 'Working title: "' + next.title + '" (you may refine the wording for SEO but keep the same topic and search intent).';

var requestBody = {
  model: 'claude-opus-4-8',
  max_tokens: 8000,
  thinking: { type: 'adaptive' },
  system: SYSTEM,
  output_config: { format: { type: 'json_schema', name: 'bournemouth_article', schema: SCHEMA } },
  messages: [{ role: 'user', content: user }]
};

return [{ json: { slug: next.slug, title: next.title, keyword: next.keyword, category: next.category, requestBody: requestBody } }];

var topic = $('Pick next topic').first().json;
var cfg = $('Config').first().json;
var resp = $json;

// 1) Extract the model's JSON.
var blocks = (resp && resp.content) || [];
var tb = null; for (var b = 0; b < blocks.length; b++) { if (blocks[b].type === 'text') { tb = blocks[b]; break; } }
if (!tb) { throw new Error('No text block in Claude response: ' + JSON.stringify(resp).slice(0, 400)); }
var content = tb.text;
var data; try { data = JSON.parse(content); } catch (e) { throw new Error('Model did not return valid JSON: ' + String(content).slice(0, 300)); }

// 2) Validate + normalise (invalid frontmatter would break the whole Astro build).
var VALID = ['things-to-do','food-and-drink','beaches','events','seasonal','family','wellness','walking','guides'];
var category = VALID.indexOf(topic.category) !== -1 ? topic.category : 'guides';
var title = String(data.title || topic.title).trim();
var description = String(data.description || '').replace(/\s+/g, ' ').trim();
if (description.length > 200) { description = description.slice(0, 197).replace(/\s+\S*$/, '') + '...'; }
if (!description) { throw new Error('Empty description'); }
var tags = Array.isArray(data.tags) ? data.tags.map(function (t) { return String(t).trim(); }).filter(Boolean).slice(0, 8) : [];
var faqs = Array.isArray(data.faqs) ? data.faqs.filter(function (f) { return f && f.question && f.answer; }).map(function (f) {
  return { question: String(f.question).replace(/\s+/g, ' ').trim(), answer: String(f.answer).replace(/\s+/g, ' ').trim() };
}) : [];
var body = String(data.body_markdown || '').trim();
if (body.length < 400) { throw new Error('Body too short (' + body.length + ' chars) — refusing to publish'); }
body = body.replace(/^# (?!#)/gm, '## ');

// 3) Hero image from images that already exist in /public/images.
var HERO = {
  'beaches':       { src: '/images/wiki/bournemouth-beach.jpg', alt: 'Bournemouth beach and seafront' },
  'things-to-do':  { src: '/images/wiki/lower-gardens.jpg', alt: 'Bournemouth Lower Gardens' },
  'food-and-drink':{ src: '/images/wiki/westbourne.jpg', alt: 'Independent cafes and dining in Bournemouth' },
  'events':        { src: '/images/wiki/air-festival.jpg', alt: 'An event on the Bournemouth seafront' },
  'seasonal':      { src: '/images/bournemouth-town-seafront-aerial.jpg', alt: 'Bournemouth seafront from above' },
  'family':        { src: '/images/wiki/oceanarium.jpg', alt: 'A family attraction in Bournemouth' },
  'wellness':      { src: '/images/wiki/southbourne-beach.jpg', alt: 'Quiet clifftop beach at Southbourne' },
  'walking':       { src: '/images/wiki/bournemouth-pier.jpg', alt: 'Bournemouth pier and promenade' },
  'guides':        { src: '/images/bournemouth-pier-and-beach.jpg', alt: 'Bournemouth pier and beach' }
};
var hero = HERO[category] || { src: '/images/bournemouth-town-seafront-aerial.jpg', alt: 'Bournemouth seafront from above' };

// 4) Assemble frontmatter (JSON.stringify => safe double-quoted YAML scalars).
var q = function (s) { return JSON.stringify(String(s)); };
var pubDate = new Date().toISOString().slice(0, 10);
var L = [];
L.push('---');
L.push('title: ' + q(title));
L.push('description: ' + q(description));
L.push('category: ' + q(category));
L.push('heroImage:');
L.push('  src: ' + q(hero.src));
L.push('  alt: ' + q(hero.alt));
L.push('pubDate: ' + pubDate);
L.push('author: "The Bournemouth Guide"');
L.push('tags: [' + tags.map(q).join(', ') + ']');
if (faqs.length) { L.push('faqs:'); faqs.forEach(function (f) { L.push('  - question: ' + q(f.question)); L.push('    answer: ' + q(f.answer)); }); }
L.push('featured: false');
L.push('draft: false');
L.push('---');
L.push('');
var fileContent = L.join('\n') + body + '\n';

return [{ json: {
  filePath: 'src/content/blog/' + topic.slug + '.md',
  fileContent: fileContent,
  commitMessage: 'content: add "' + title + '" (automated)',
  owner: cfg.owner, repo: cfg.repo, branch: cfg.branch, slug: topic.slug
} }];
